import{_ as n,C as o,o as s,c as l,j as t,a as d,E as a,al as c}from"./chunks/framework.Cru2ZAWp.js";const y=JSON.parse('{"title":"Firmware Update (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/dfu.md","filePath":"examples/dfu.md"}'),p={name:"examples/dfu.md"};function u(h,e,f,m,g,b){const r=o("DfuDemo"),i=o("BoksDashboard");return s(),l("div",null,[e[0]||(e[0]=t("h1",{id:"firmware-update-dfu",tabindex:"-1"},[d("Firmware Update (DFU) "),t("a",{class:"header-anchor",href:"#firmware-update-dfu","aria-label":'Permalink to "Firmware Update (DFU)"'},"​")],-1)),a(r),e[1]||(e[1]=c('<p>This interactive demo allows you to update the firmware on your Boks device. It uses the <code>@thib3113/web-bluetooth-dfu</code> library to securely flash Nordic Semiconductor <code>.zip</code> update packages.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The firmware update is a two-step process:</p><ol><li><p><strong>Preparation (Normal Mode)</strong>:</p><ul><li>When you connect to your Boks device (e.g., <code>Boks-1234</code>), the tool reads current hardware, software versions, and battery level.</li><li>If the battery is below 20%, you&#39;ll be warned to change it before proceeding.</li><li>Pressing &quot;Enter DFU Mode&quot; writes <code>0x01</code> to the DFU control characteristic, causing the device to reboot into a specialized bootloader state.</li></ul></li><li><p><strong>Flashing (DFU Mode)</strong>:</p><ul><li>Once the device reboots, you will be disconnected.</li><li>Re-open the connection panel and connect to the device again (it will advertise as <code>DfuTarg</code> or <code>Boks_DFU</code>).</li><li>You can immediately select your firmware <code>.zip</code> file and start the flashing process.</li><li>The device will reboot back to normal operation once the transfer is verified and complete.</li></ul></li></ol><h2 id="crucial-faq-safety-information" tabindex="-1">Crucial FAQ &amp; Safety Information <a class="header-anchor" href="#crucial-faq-safety-information" aria-label="Permalink to &quot;Crucial FAQ &amp; Safety Information&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Recovery from Interruption</p><p>Not all Boks devices recover from an interrupted DFU in the same way.</p><ul><li><strong>Boks V3 (nRF52811)</strong>: If the update is interrupted (browser closed, power loss), the device will be <strong>temporarily unavailable</strong> and stuck in update mode. It stays in the bootloader state, preventing any normal interaction until a successful flash is performed.</li><li><strong>Boks V4 (nRF52833)</strong>: The bootloader on newer devices handles interruptions more gracefully. A battery pull (removing and re-inserting the batteries) can usually recover the device to its previous state.</li></ul></div><p><strong>Q: Can I flash an older version (downgrade)?</strong> A: Usually, no. The bootloader contains downgrade protection (Error <code>0x0E</code>). You can only flash versions equal to or greater than your current installation.</p><p><strong>Q: What happens if I flash a firmware not signed by Boks?</strong> A: The DFU bootloader requires cryptographically signed firmware packages. Flashing unsigned or improperly signed zips will result in an Authentication Error (<code>0x0C</code>).</p>',8)),a(i)])}const v=n(p,[["render",u]]);export{y as __pageData,v as default};
